import z from 'zod';

/**
 * Prepend https:// to bare domains so URL.canParse / new URL() work.
 * Localhost and 127.0.0.1 get http:// instead.
 */
export function ensureProtocol(target: string): string {
  const trimmed = target.trim();
  if (/^https?:\/\//i.test(trimmed)) return trimmed;
  const host = trimmed.split('/')[0] ?? '';
  const hostname = host.split(':')[0] ?? '';
  const isLocal =
    hostname === 'localhost' || hostname === '127.0.0.1' || hostname === '::1';
  return `${isLocal ? 'http' : 'https'}://${trimmed}`;
}

/**
 * Zod schema that accepts bare domains (e.g. "stableenrich.dev") and full URLs.
 * Normalizes with {@link ensureProtocol} then validates as a URL.
 */
export const zodUrl = z.string().transform(ensureProtocol).pipe(z.url());
